// Input: Array of products from Shopify Scraper
// Output: SKU → Shopify handle mappings

const products = $input.all();
const mappings = [];

for (const item of products) {
  const product = item.json;
  const handle = product.shopify_handle;
  const skus = product.skus || [];
  const vendorId = product.vendor_id;
  const productUrl = product.product_url;
  const productName = product.product_name;

  // Create a mapping for each SKU
  for (const sku of skus) {
    if (sku && sku.trim()) {
      mappings.push({
        sku: sku.trim(),
        vendor_id: vendorId,
        shopify_handle: handle,
        product_url: productUrl,
        product_name: productName,
        mapping_type: 'shopify',
        created_at: new Date().toISOString()
      });
    }
  }

  // Also handle products with multiple variants
  const variants = product.variants || [];
  for (const variant of variants) {
    if (variant.sku && variant.sku.trim()) {
      const variantSku = variant.sku.trim();

      // Check if we already added this SKU
      const exists = mappings.find(m => m.sku === variantSku && m.vendor_id === vendorId);

      if (!exists) {
        mappings.push({
          sku: variantSku,
          vendor_id: vendorId,
          shopify_handle: handle,
          product_url: productUrl,
          product_name: productName,
          variant_title: variant.title,
          variant_id: variant.id,
          mapping_type: 'shopify_variant',
          created_at: new Date().toISOString()
        });
      }
    }
  }
}

return mappings.map(m => ({ json: m }));

// Aggregate statistics about the mappings
const items = $input.all();

const stats = {
  total_mappings: items.length,
  unique_skus: new Set(items.map(i => i.json.sku)).size,
  unique_vendors: new Set(items.map(i => i.json.vendor_id)).size,
  unique_products: new Set(items.map(i => i.json.shopify_handle)).size,
  mapping_types: {},
  timestamp: new Date().toISOString()
};

// Count mapping types
for (const item of items) {
  const type = item.json.mapping_metadata?.mapping_type || 'unknown';
  stats.mapping_types[type] = (stats.mapping_types[type] || 0) + 1;
}

return [{ json: stats }];
